var utils = {
	PAD_LEFT	: 'left',
	PAD_RIGHT	: 'right',
	PAD_BOTH	: 'both',

	pad 			: function(value, char, length, side) {
		side = typeof side === 'undefined' ? 'right' : side;

		value = (value)?value:'';

		var padding = '';
		var required = Math.floor(length) - value.toString().length;

		while (required > 0) {
			required -= 1;

			if (side === this.PAD_LEFT) value = char + value;
			if (side === this.PAD_RIGHT) value = value + char;

			if (side === this.PAD_BOTH) {
				if (required % 2 === 0) value = char + value;
				else value = value + char;
			}
		}

		return value;
	}
};

var formatters = {
	empty 	: function(chunk,config) {
		return utils.pad('', config.space, config.width, utils.PAD_RIGHT);
	},

	ruler 	: function(chunk,config) {
		return utils.pad('', config.ruler, config.width, utils.PAD_RIGHT);
	},

	logo 		: function(chunk,config){
		return '<div style="text-align: center;"><img src="'+chunk.value+'" width="'+chunk.width+'" height="'+chunk.height+'"></div>'+config.EOL;
	},

	text 		: function(chunk,config) {
		if ($.isArray(chunk.value)) {
			// Expand array to multiple text calls with same formatting.
		      var arrays 	= [];
		      var tis 		= this;
		      $.each(chunk.value,function(i,value){
		      	arrays.push(formatters.text({ type: chunk.type, value: value, align: chunk.align, padding: chunk.padding },config));
		      });
		      arrays = arrays.join(config.EOL);
		      return arrays;
		}

		var chars = config.width - (chunk.hasOwnProperty('padding') ? (chunk.hasOwnProperty('align') && chunk.align === 'center' ? chunk.padding * 2 : chunk.padding) : 0);
		
		if(!chunk.hasOwnProperty('value') || !chunk.value){
			return;
		}

		chunk.value = chunk.value.toString();

		var words = chunk.value.split(/\s/g);
		var lines = [];
		var line = '';

		words.reverse();

		while (words.length > 0) {
			var word = words.pop();

			if (line.length + word.length > chars) {
				lines.push(line);
				line = '';
			}

			line += word + config.space;
		}

		lines.push(line);

		var alignTypes = {
			left: utils.PAD_RIGHT,
			right: utils.PAD_LEFT,
			center: utils.PAD_BOTH
		};

		if (lines) {
			return lines.map(function(line){
				line = line.replace(/\s+$|^\s+/, '');

				if (chunk.hasOwnProperty('align')) {
					if (alignTypes.hasOwnProperty(chunk.align)) {
						return utils.pad(line, config.space, config.width, alignTypes[chunk.align]);
					}
				}

				return utils.pad(line, config.space, config.width, utils.PAD_RIGHT);
			}).join(config.EOL);
		}

		return '';
	},
  
	calcSpace 		: function(percent,full){
		return Math.round((full*percent)/100);
	},

	calcSpaceA 		: function(percent,full,subsIndx){
		var arr = [];
		var count = 0;

		for(var i = 0; i < percent.length;i++){
			var calc = Math.round((full*percent[i])/100);
			arr[i] = calc;
			count += calc;
		}

		if(count > full){
			var left = count-full;
			arr[subsIndx] = arr[subsIndx]-left;
		}
		return arr;
	},

	properties 		: function(chunk,config) {    
	    var arrays = [];
	    var tis = this;
	    $.each(chunk.lines,function(i,liney){
	    	var name 	= (liney.name && liney.name != 'undefined')?liney.name:false;
	    	var value 	= (liney.value && liney.value != 'undefined')?liney.value:'';
	    	if(name){
		      	arrays.push(utils.pad(name + ':', config.space, formatters.calcSpace(50,config.width),utils.PAD_LEFT) + utils.pad(value, config.space, formatters.calcSpace(50,config.width),liney.align));
		    }
	    });
	    
	    if(arrays.length > 0){
		    arrays = arrays.join(config.EOL);
		    return arrays;
		}

	    return;
	},

	table 			: function(chunk,config) {
		var lines = [];

		//for (var line of chunk.lines) {
		$.each(chunk.lines,function(i,line){
			var itm 	= (line.item && line.item != 'undefined')?line.item:'';
			var tax 	= (line.tax && line.tax != 'undefined')?line.tax:'';
			var qty 	= (line.qty && line.qty != 'undefined')?line.qty:'';
			var code 	= (line.code && line.code != 'undefined')?line.code:'';
			var cost 	= (line.cost && line.cost != 'undefined')?line.cost:'';
			var total 	= (line.total && line.total != 'undefined')?line.total:'';

			if(itm || tax){
				let desiredLength = config.width;
				let itmSubstring = itm.substr(0, config.width);
				let taxPadding = utils.pad(tax, config.space, desiredLength - itmSubstring.length, utils.PAD_LEFT);

				let line = itmSubstring + taxPadding;

				// Asegurarse de que la línea tenga exactamente 32 caracteres
				if (line.length < desiredLength) {
					line += config.space.repeat(desiredLength - line.length);
				} else if (line.length > desiredLength) {
					line = line.substr(0, desiredLength);
				}

				lines.push(line);
	      		// lines.push([
				// 	utils.pad(itm.substr(0, config.width), config.space, config.width, utils.PAD_RIGHT),
				// 	utils.pad(tax, config.space, 4, utils.PAD_LEFT)
				// ].join(''));
	      	}

      		if(qty || code || cost || total){
	      		var arrSpace = formatters.calcSpaceA([18,28,24,30],config.width,1);
				lines.push([
					utils.pad(qty, config.space, arrSpace[0], utils.PAD_LEFT),
					utils.pad(code, config.space, arrSpace[1], utils.PAD_RIGHT),
					utils.pad(cost, config.space, arrSpace[2], utils.PAD_LEFT),
	        		utils.pad(total, config.space, arrSpace[3], utils.PAD_LEFT)
				].join(''));
			}

			if (line.hasOwnProperty('discount') && line.discount.value) {
				var discountText =  line.discount.hasOwnProperty('message')	? formatters.text({ type: 'text', value: line.discount.message, align: 'left', padding:3 },config)	: '';

				lines.push([
					//utils.pad(discountText.substr(0, config.width - 2), config.space, config.width - 2, utils.PAD_RIGHT)
					discountText
					
				].join(''));
			}
		});

		return lines.join(config.EOL);
	}
};

var receipt = {
	config: {
		width 	: 50,
		ruler 	: '=',
    	EOL 	: '\n',
    space 	: ' '
	},

	create 		: function(chunks) {
	    var arrays 	= [];
	    var tis 		= this;
	    $.each(chunks,function(i,chunk){

	      if (chunk.hasOwnProperty('type')) {
	      	if(chunk.type == 'text'){
	        	arrays.push(formatters.text(chunk, tis.config));
	        }else if(chunk.type == 'empty'){
	        	arrays.push(formatters.empty(chunk, tis.config));
	        }else if(chunk.type == 'ruler'){
	        	arrays.push(formatters.ruler(chunk, tis.config));
	        }else if(chunk.type == 'properties'){ 
	        	arrays.push(formatters.properties(chunk, tis.config));
	        }else if(chunk.type == 'table'){
	        	arrays.push(formatters.table(chunk, tis.config));
	        }else if(chunk.type == 'logo'){
	        	arrays.push(formatters.logo(chunk, tis.config));
	        }else{
	        	arrays.push('');
	        }
				}
				return '';
	    });
	    arrays = arrays.join(tis.config.EOL);
	    return arrays;
	}
};
